function findBenefitBox(card){const w=card.width,h=card.height,roi={x:0,y:0,w,h},arr=comps(card,(r,g,b)=>r>90&&r>g*1.15&&r>b*1.15&&sat(r,g,b)>35,roi,2,Math.max(18,Math.round(w*h*.0004))).map(r=>({...r,fill:r.area/Math.max(1,(r.w/2)*(r.h/2)),cx:(r.x+r.w/2)/w,cy:(r.y+r.h/2)/h})).filter(r=>r.w>w*.18&&r.h>h*.12&&r.w<w*.62&&r.h<h*.55&&r.cx>.52&&r.cy>.48&&r.fill>.48);arr.sort((a,b)=>(b.fill*4+b.cx+b.cy+b.w/w+b.h/h)-(a.fill*4+a.cx+a.cy+a.w/w+a.h/h));const r=arr[0];return r?clipR({x:r.x-10,y:r.y-10,w:r.w+20,h:r.h+20},w,h):clipR({x:w*.42,y:h*.40,w:w*.57,h:h*.59},w,h)}
function prepForOcr(c,scale=4,contrast=1.45){const o=document.createElement('canvas');o.width=Math.max(1,Math.round(c.width*scale));o.height=Math.max(1,Math.round(c.height*scale));const x=o.getContext('2d');x.fillStyle='#fff';x.fillRect(0,0,o.width,o.height);x.filter=`grayscale(1) contrast(${contrast})`;x.drawImage(c,0,0,o.width,o.height);return o}

function erode(mask,w,h,r=2){const out=new Uint8Array(mask.length);for(let y=r;y<h-r;y++)for(let x=r;x<w-r;x++){let ok=1;for(let yy=-r;yy<=r&&ok;yy++)for(let xx=-r;xx<=r;xx++)if(!mask[(y+yy)*w+x+xx]){ok=0;break}out[y*w+x]=ok}return out}
function dilate(mask,w,h,r=2){const out=new Uint8Array(mask.length);for(let y=0;y<h;y++)for(let x=0;x<w;x++){let ok=0;for(let yy=-r;yy<=r&&!ok;yy++){const ny=y+yy;if(ny<0||ny>=h)continue;for(let xx=-r;xx<=r;xx++){const nx=x+xx;if(nx>=0&&nx<w&&mask[ny*w+nx]){ok=1;break}}}out[y*w+x]=ok}return out}
function maskComponents(mask,w,h,minA=20){const seen=new Uint8Array(mask.length),out=[],dirs=[[1,0],[-1,0],[0,1],[0,-1]];for(let y=0;y<h;y++)for(let x=0;x<w;x++){const idx=y*w+x;if(!mask[idx]||seen[idx])continue;const q=[[x,y]];seen[idx]=1;let qi=0,a=0,minX=x,minY=y,maxX=x,maxY=y;while(qi<q.length){const[cx,cy]=q[qi++];a++;minX=Math.min(minX,cx);minY=Math.min(minY,cy);maxX=Math.max(maxX,cx);maxY=Math.max(maxY,cy);for(const[dx,dy]of dirs){const nx=cx+dx,ny=cy+dy;if(nx<0||ny<0||nx>=w||ny>=h)continue;const ni=ny*w+nx;if(mask[ni]&&!seen[ni]){seen[ni]=1;q.push([nx,ny])}}}if(a>=minA)out.push({x:minX,y:minY,w:maxX-minX+1,h:maxY-minY+1,area:a})}return out}
function denseBadgeInfo(benefit){const w=benefit.width,h=benefit.height,d=benefit.getContext('2d',{willReadFrequently:true}).getImageData(0,0,w,h).data,mask=new Uint8Array(w*h);for(let y=0;y<h;y++)for(let x=0;x<w;x++){const i=(y*w+x)*4,r=d[i],g=d[i+1],b=d[i+2];if(r>90&&r>g*1.16&&r>b*1.16&&sat(r,g,b)>35)mask[y*w+x]=1}const opened=dilate(erode(mask,w,h,2),w,h,2),cand=maskComponents(opened,w,h,Math.max(20,Math.round(w*h*.01))).map(r=>({...r,fill:r.area/(r.w*r.h),cx:(r.x+r.w/2)/w,cy:(r.y+r.h/2)/h})).filter(r=>r.w>w*.25&&r.h>h*.25&&r.fill>.60&&r.cx>.45&&r.cy>.45).sort((a,b)=>(b.fill*5+b.area/(w*h)+b.cx+b.cy)-(a.fill*5+a.area/(w*h)+a.cx+a.cy));if(!cand.length)return null;const r=cand[0],badge=crop(benefit,r,3),bw=badge.width,bh=badge.height,margin=Math.max(3,Math.round(Math.min(bw,bh)*.08)),id=badge.getContext('2d',{willReadFrequently:true}).getImageData(margin,margin,Math.max(1,bw-margin*2),Math.max(1,bh-margin*2)).data,iw=Math.max(1,bw-margin*2),ih=Math.max(1,bh-margin*2),wm=new Uint8Array(iw*ih);for(let y=0;y<ih;y++)for(let x=0;x<iw;x++){const i=(y*iw+x)*4,rr=id[i],gg=id[i+1],bb=id[i+2];if(rr>165&&gg>165&&bb>165&&sat(rr,gg,bb)<95)wm[y*iw+x]=1}let maxGlyph=0;for(const c of maskComponents(wm,iw,ih,8)){if(c.x>0&&c.y>0&&c.x+c.w<iw&&c.y+c.h<ih)maxGlyph=Math.max(maxGlyph,c.h/ih)}if(maxGlyph<=.36){freeCanvas(badge);return null}const td=badge.getContext('2d',{willReadFrequently:true}).getImageData(Math.round(bw*.05),Math.round(bh*.05),Math.max(1,Math.round(bw*.90)),Math.max(1,Math.round(bh*.33))).data;let whiteInk=0;for(let i=0;i<td.length;i+=4)if(td[i]>165&&td[i+1]>165&&td[i+2]>165&&sat(td[i],td[i+1],td[i+2])<105)whiteInk++;return{badge,topInk:whiteInk/(td.length/4),box:r}}

const thaiDigits={'๐':'0','๑':'1','๒':'2','๓':'3','๔':'4','๕':'5','๖':'6','๗':'7','๘':'8','๙':'9'};
function cleanOcr(raw){let s=String(raw||'').replace(/[๐-๙]/g,d=>thaiDigits[d]||d).replace(/[|_=~—–]+/g,' ').replace(/ล\s*ด/g,'ลด').replace(/ฟ\s*รี/g,'ฟรี').replace(/ซื\s*้\s*อ/g,'ซื้อ');s=s.replace(/\b(?:an|aN|aA|AA|A4|4A|a4)\s*(?=\d+\s*%)/gi,'ลด ').replace(/\b(?:WS|ws)\s*(?=\d+)/g,'ฟรี ').replace(/(?:ข\s*บ?\s*วด|[ยบผ]วด|\b(?:UOA|UDA|UIA|YOA|YOM|von)\b)/gi,'ขวด').replace(/(?:ช\s*ิ?\s*้?\s*น|\b(?:Bu|GU|Gu|6u|bu|ชีน|ซิน|ขิน|ชน)\b)/gi,'ชิ้น').replace(/(?:แพ\s*็?\s*ค|\b(?:แพค|เเพ็ค|ulin)\b)/gi,'แพ็ค').replace(/(?:ล|ส)\s*ั?\s*ง/g,'ลัง').replace(/ก\s*ล\s*่?\s*อ\s*ง/g,'กล่อง').replace(/\b(?:av|a0)\b/gi,'ลัง').replace(/(\d{1,2})\s*[°º]/g,'$1%').replace(/\bB%/gi,'8%').replace(/ลด\s*(\d{1,2})9\b/g,'ลด $1%').replace(/ลด\s*(\d{1,2})(?=\s*$)/g,(m,n)=>ALLOWED_PCT.has(Number(n))?`ลด ${n}%`:m);return s.replace(/\s+/g,' ').trim()}
function parseTiers(raw){const s=cleanOcr(raw),unit='(ขวด|ชิ้น|แพ็ค|กล่อง|ลัง|ซอง|ถุง)',hits=[];for(const m of s.matchAll(new RegExp('(?:ซื้อ\\s*)?(\\d{1,3})\\s*'+unit+'.{0,12}?ฟรี\\s*(\\d{1,3})\\s*(?:'+unit+')?\\s*(?:\\((\\d{1,2})\\s*%\\))?','g')))hits.push({p:m.index,v:['free',Number(m[1]),m[2],Number(m[3]),m[4]||m[2],m[5]?Number(m[5]):null]});for(const m of s.matchAll(new RegExp('(\\d{1,3})\\s*-\\s*(\\d{1,3})\\s*'+unit+'.{0,8}?ลด\\s*(\\d{1,2})\\s*%','g')))hits.push({p:m.index,v:['range',Number(m[1]),Number(m[2]),m[3],Number(m[4])]});for(const m of s.matchAll(new RegExp('(\\d{1,3})\\s*'+unit+'.{0,8}?ลด\\s*(\\d{1,2})\\s*%','g'))){if(!hits.some(h=>Math.abs(h.p-m.index)<5&&(h.v[0]==='free'||h.v[0]==='range')))hits.push({p:m.index,v:['discount',Number(m[1]),m[2],Number(m[3])]})}hits.sort((a,b)=>a.p-b.p);const out=[];for(const h of hits)if(!out.some(x=>JSON.stringify(x)===JSON.stringify(h.v)))out.push(h.v);if(!out.length){const p=pctSig(s);if(p.length===1)out.push(['simple',p[0]])}return out}
function pctSig(s){return[...cleanOcr(s).matchAll(/(\d{1,2})\s*%/g)].map(m=>Number(m[1])).filter(n=>n>0&&n<100)}
function quantitySig(s){const c=cleanOcr(s),q=[...c.matchAll(/(\d{1,3})\s*(?:ขวด|ชิ้น|แพ็ค|กล่อง|ลัง|ซอง|ถุง)/g)].map(m=>Number(m[1])),p=pctSig(c);if(q.length<p.length)for(const m of c.matchAll(/(\d{1,3})\s+.{0,8}?ลด\s*\d{1,2}\s*%/g)){if(q.length>=p.length)break;q.push(Number(m[1]))}return q}
function lcs(a,b){const dp=Array(b.length+1).fill(0);for(const x of a){let prev=0;for(let j=1;j<=b.length;j++){const old=dp[j];dp[j]=x===b[j-1]?prev+1:Math.max(dp[j],dp[j-1]);prev=old}}return dp.at(-1)}
function templateScore(raw,label){const rt=parseTiers(raw),lt=parseTiers(label);if(rt.length&&JSON.stringify(rt)===JSON.stringify(lt))return 10;const rp=pctSig(raw),lp=pctSig(label),rq=quantitySig(raw),lq=quantitySig(label),ps=lcs(rp,lp)/Math.max(1,rp.length,lp.length)-.25*Math.abs(rp.length-lp.length),qs=lcs(rq,lq)/Math.max(1,rq.length,lq.length)-.18*Math.abs(rq.length-lq.length);return .62*ps+.33*qs+.05*(rt.length===lt.length?1:0)}
function bestTemplate(raw){const ranked=FUNCTION_TEMPLATES.map(label=>({label,score:templateScore(raw,label)})).sort((a,b)=>b.score-a.score||a.label.localeCompare(b.label));return{...ranked[0],margin:ranked[0].score-(ranked[1]?.score??0)}}
function parseBadgePercent(raw){const nums=String(raw||'').match(/\d{1,4}/g)||[];if(!nums.length)return null;const n=nums[0],cand=[];for(let i=0;i<n.length;i++)for(let j=i+1;j<=Math.min(n.length,i+2);j++){const v=Number(n.slice(i,j));if(ALLOWED_PCT.has(v))cand.push({len:j-i,pos:i,v})}cand.sort((a,b)=>b.len-a.len||a.pos-b.pos);return cand[0]?.v??null}
